item.description:
 &lt;h2 id=&#34;corepress主题优化概述&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#corepress主题优化概述&#34;&gt;#&lt;/a&gt; CorePress 主题优化概述&lt;/h2&gt;
&lt;p&gt;优化内容:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;加入了 font-display: swap; 属性，可确保在加载 Web 字体时用户可见文本.&lt;/li&gt;
&lt;li&gt;压缩了 CSS 文件&lt;/li&gt;
&lt;li&gt;利用 Nginx 可对 js 以及字体文件进行本地缓存&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;webfonts字体优化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#webfonts字体优化&#34;&gt;#&lt;/a&gt; Webfonts 字体优化&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;# 下载fonts文件到主题目录下
wget -P /wp-content/themes/CorePress/static https://github.com/JiangJiYue/yunwei/blob/main/webfonts.tar.gz
# 解压
tar -zxvf /wp-content/themes/CorePress/static/webfonts.tar.gz
# 删除压缩包
rm -rf /wp-content/themes/CorePress/static/webfonts.tar.gz
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;/p&gt;
&lt;h2 id=&#34;css文件优化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#css文件优化&#34;&gt;#&lt;/a&gt; Css 文件优化&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;# 下载css文件到主题目录下
wget -P /wp-content/themes/CorePress/static/css/ https://raw.githubusercontent.com/JiangJiYue/yunwei/main/all.min.css
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;/p&gt;
&lt;h2 id=&#34;utils-php文件优化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#utils-php文件优化&#34;&gt;#&lt;/a&gt; Utils php 文件优化&lt;/h2&gt;
&lt;p&gt;替换 &lt;code&gt;utils.php&lt;/code&gt;  中 &lt;code&gt;loadiconfont_by_cdn&lt;/code&gt;  函数内容 &lt;code&gt;vim /wp-content/themes/CorePress/geekframe/utils.php&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function loadiconfont_by_cdn()
&amp;#123;
     echo &#39;&amp;lt;link rel=&amp;quot;stylesheet&amp;quot; href=&amp;quot;/wp-content/themes/CorePress/static/css/all.min.css?v=&#39; . THEME_VERSIONNAME . &#39;&amp;quot;&amp;gt;&#39;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;/p&gt;
&lt;h2 id=&#34;优化header-php文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#优化header-php文件&#34;&gt;#&lt;/a&gt; 优化 Header php 文件&lt;/h2&gt;
&lt;p&gt;如果不想用主题提供的字体也可以将 &lt;code&gt;header.php&lt;/code&gt;  文件中的以下内容注释掉 &lt;code&gt;vim /wp-content/themes/CorePress/header.php&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if ($set[&#39;theme&#39;][&#39;font&#39;] != &#39;no&#39;) &amp;#123;
     echo &#39;&amp;lt;link rel=&amp;quot;stylesheet&amp;quot; type=&amp;quot;text/css&amp;quot; href=&amp;quot;https://cdn.jsdelivr.net/gh/ghboke/corepresscdn@master/static/lib/font/&#39; . $set[&#39;theme&#39;][&#39;font&#39;] . &#39;/font.css&amp;quot;&amp;gt;&#39;;
     ?&amp;gt;
     &amp;lt;style&amp;gt;
         html, textarea &amp;#123;
             font-family: &amp;lt;?php echo $set[&#39;theme&#39;][&#39;font&#39;]?&amp;gt;, PingFang\ SC, Hiragino\ Sans\ GB, Microsoft\ YaHei, STHeiti, WenQuanYi\ Micro\ Hei, Helvetica, Arial, sans-serif !important;
        &amp;#125;
     &amp;lt;/style&amp;gt;
     &amp;lt;?php
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;优化nginx-conf文化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#优化nginx-conf文化&#34;&gt;#&lt;/a&gt; 优化 Nginx Conf 文化&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;#缓存静态文件
 location ~ .*\.(gifjpgjpegpngbmpicowebp)$ &amp;#123;
     root 网站根目录;
     expires 30d;
&amp;#125;
 #缓存静态文件
location ~ .*\.(eotwoffwoff2ttf)$ &amp;#123;
     root 网站根目录;
     expires 30d;
&amp;#125;
 ​
# expires 30s; 30秒
# expires 30m; 30分钟
# expires 2h; 2个小时
# expires 30d; 30天
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;优化主页缩略图alt&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#优化主页缩略图alt&#34;&gt;#&lt;/a&gt; 优化主页缩略图 alt&lt;/h2&gt;
&lt;p&gt;给 &lt;code&gt;/wp-content/themes/CorePress/component/post-list-item.php&lt;/code&gt;  中的 &lt;code&gt;$imgtag&lt;/code&gt;  变量添加 &lt;code&gt;alt&lt;/code&gt;  属性， &lt;code&gt;alt&lt;/code&gt;  内容为当前文章的标题&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 修改后的代码
if ($set[&#39;module&#39;][&#39;imglazyload&#39;] == 1) &amp;#123;
     $pathname = &#39;data-original&#39;;
     $imgtag = &#39;&amp;lt;img src=&amp;quot;&#39; . file_get_img_url(&#39;loading.gif&#39;) . &#39;&amp;quot; data-original=&amp;quot;&#39; . $postitem[&#39;thumbnail&#39;] . &#39;&amp;quot; alt=&amp;quot;&#39;.$postitem[&#39;title&#39;] .&#39;&amp;quot;&amp;gt;&#39;;
&amp;#125; else &amp;#123;
     $imgtag = &#39;&amp;lt;img src=&amp;quot;&#39; . $postitem[&#39;thumbnail&#39;] . &#39;&amp;quot;alt=&amp;quot;&#39;.$postitem[&#39;title&#39;] .&#39;&amp;quot;&amp;gt;&#39;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;优化友情链接无ul&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#优化友情链接无ul&#34;&gt;#&lt;/a&gt; 优化友情链接无 ul&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;/wp-content/themes/CorePress/index.php&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;div class=&amp;quot;frinds-links-list&amp;quot;&amp;gt;
     &amp;lt;ul&amp;gt;
    &amp;lt;?php wp_list_bookmarks(&#39;title_li=&amp;amp;categorize=0&amp;amp;show_images=0&amp;amp;category=&#39; . $set[&#39;index&#39;][&#39;links_ids&#39;]); ?&amp;gt;
     &amp;lt;/ul&amp;gt;
&amp;lt;/div&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;wp-content/themes/CorePress/static/css/main.css&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/*文件中的.frinds-links li Css样式替换为下面 */
.frinds-links li&amp;#123;float: left;font-size:15px;list-style:none;margin-right:20px;margin-bottom:6px;vertical-align:middle&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;h3 id=&#34;什么是网关&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是网关&#34;&gt;#&lt;/a&gt; 什么是网关&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在传统&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvVENQL0lQ&#34;&gt; TCP/IP&lt;/span&gt; 术语中，网络设备只分成两种，一种为网关 (gateway), 另一种为主机 (host). 网关能在网络间转递数据包，但主机不能转送数据包。在主机 (又称终端系统，end system) 中，数据包需经过 TCP/IP 四层协议处理，但是在网关 (又称中介系统，intermediate system) 只需要到达&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3cvaW5kZXgucGhwP3RpdGxlPSVFNyVCNiVCMiVFOSU5QSU5QiVFNSVCMSVBNCZhbXA7YWN0aW9uPWVkaXQmYW1wO3JlZGxpbms9MQ==&#34;&gt;网际层&lt;/span&gt; (Internet layer), 决定路径之后就可以转送。在当时，网关 (gateway) 与路由器 (router) 还没有区别.&lt;/p&gt;
&lt;p&gt;在现代网络术语中，网关 (gateway) 与路由器 (router) 的定义不同。网关 (gateway) 能在不同&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU3JUJEJTkxJUU3JUJCJTlDJUU0JUJDJUEwJUU4JUJFJTkzJUU1JThEJThGJUU4JUFFJUFF&#34;&gt;协议&lt;/span&gt;间移动资料，而路由器 (router) 是在不同&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU3JUI2JUIyJUU4JUI3JUFG&#34;&gt;网络&lt;/span&gt;间移动资料，相当于传统所说的 IP 网关 (IP gateway).&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;网关&lt;/strong&gt;顾名思义就是连接两个网络的设备，对于语音网关来说，他可以连接&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvUFNUTg==&#34;&gt; PSTN&lt;/span&gt; 和&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU0JUJCJUE1JUU1JUE0JUFBJUU3JUJEJTkx&#34;&gt;以太网&lt;/span&gt;，这就相当于&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvVk9JUA==&#34;&gt; VOIP&lt;/span&gt;, 把不同电话中的模拟信号通过网关而转换成数字信号，而且加入协议再去传输。在到了接收端的时候再通过&lt;strong&gt;网关&lt;/strong&gt;还原成模拟的电话信号，最后才能在电话机上听到.&lt;/p&gt;
&lt;p&gt;对于以太网中的&lt;strong&gt;网关&lt;/strong&gt;只能转发三层以上数据包，这一点和路由是一样的。而不同的是&lt;strong&gt;网关&lt;/strong&gt;中并没有&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU4JUI3JUFGJUU3JTk0JUIxJUU4JUExJUE4&#34;&gt;路由表&lt;/span&gt;，他只能按照预先设定的不同网段来进行转发。网关最重要的一点就是端口映射，子网内用户在外网看来只是外网的 IP 地址对应着不同的端口，这样看来就会保护子网内的用户.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;单节点场景&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#单节点场景&#34;&gt;#&lt;/a&gt; 单节点场景&lt;/h3&gt;
&lt;p&gt;&lt;a href=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/archives/422/attachment/1&#34;&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/1.webp&#34; alt=&#34;&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;多节点场景&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多节点场景&#34;&gt;#&lt;/a&gt; 多节点场景&lt;/h3&gt;
&lt;p&gt;&lt;a href=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/archives/422/attachment/2&#34;&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/2.webp&#34; alt=&#34;&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;网关作用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#网关作用&#34;&gt;#&lt;/a&gt; 网关作用&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;统一入口&lt;/li&gt;
&lt;li&gt;安全：黑名单、权限身份认证&lt;/li&gt;
&lt;li&gt;限流：实现微服务访问流量计算，基于流量计算分析进行限流，可以定义多种限流规则&lt;/li&gt;
&lt;li&gt;缓存：数据缓存&lt;/li&gt;
&lt;li&gt;日志：日志记录&lt;/li&gt;
&lt;li&gt;监控：记录请求响应数据，api 耗时分析，性能监控&lt;/li&gt;
&lt;li&gt;重试：异常重试&lt;/li&gt;
&lt;li&gt;熔断：降级&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;现有框架&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#现有框架&#34;&gt;#&lt;/a&gt; 现有框架&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Tyk: Tyk 是一个开放源码的 API 网关，它是快速、可扩展和现代的.Tyk 提供了一个 API 管理平台，其中包括 API 网关、API 分析、开发人员门户和 API 管理面板.Trk 是一个基于 Go 实现的网关服务.&lt;/li&gt;
&lt;li&gt;Kong: Kong 是一个可扩展的开放源码 API Layer (也称为 API 网关或 API 中间件).Kong 在任何 RESTful API 的前面运行，通过插件扩展，它提供了超越核心平台的额外功能和服务.&lt;/li&gt;
&lt;li&gt;Orange: 和 Kong 类似也是基于 OpenResty 的一个 API 网关程序，是由国人开发的.&lt;/li&gt;
&lt;li&gt;Netflix zuul:Zuul 是一种提供动态路由、监视、弹性、安全性等功能的边缘服务.Zuul 是 Netflix 出品的一个基于 JVM 路由和服务端的负载均衡器.&lt;/li&gt;
&lt;li&gt;apiaxle: Nodejs 实现的一个 API 网关.&lt;/li&gt;
&lt;li&gt;api-umbrella: Ruby 实现的一个 API 网关.&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;技术选型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#技术选型&#34;&gt;#&lt;/a&gt; 技术选型&lt;/h3&gt;
&lt;p&gt;&lt;a href=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/archives/422/3-3&#34;&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/3-1.webp&#34; alt=&#34;&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;正向代理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#正向代理&#34;&gt;#&lt;/a&gt; 正向代理&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;代理 (英语：Proxy), 也称网络代理，是一种特殊的网络服务，允许一个网络终端 (一般为客户端) 通过这个服务与另一个网络终端 (一般为服务器) 进行非直接的连接。一些网关、路由器等网络设备具备网络代理功能。一般认为代理服务有利于保障网络终端的隐私或安全，防止攻击.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/archives/422/attachment/4&#34;&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/4.webp&#34; alt=&#34;&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;反向代理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反向代理&#34;&gt;#&lt;/a&gt; 反向代理&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;反向代理&lt;/strong&gt;在&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU3JTk0JUI1JUU4JTg0JTkxJUU3JUJEJTkxJUU3JUJCJTlD&#34;&gt;电脑网络&lt;/span&gt;中是&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU0JUJCJUEzJUU3JTkwJTg2JUU0JUJDJUJBJUU2JTlDJThEJUU1JTk5JUE4&#34;&gt;代理服务器&lt;/span&gt;的一种。服务器根据客户端的请求，从其关系的一组或多组后端&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU2JTlDJThEJUU1JThBJUExJUU1JTk5JUE4&#34;&gt;服务器&lt;/span&gt; (如&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvV2ViJUU2JTlDJThEJUU1JThBJUExJUU1JTk5JUE4&#34;&gt; Web 服务器&lt;/span&gt;) 上获取资源，然后再将这些资源返回给客户端，客户端只会得知反向代理的 IP 地址，而不知道在代理服务器后面的服务器集群的存在 [&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU1JThGJThEJUU1JTkwJTkxJUU0JUJCJUEzJUU3JTkwJTg2I2NpdGVfbm90ZS0x&#34;&gt;1]&lt;/span&gt;.&lt;/p&gt;
&lt;p&gt;与&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU1JTg5JThEJUU1JTkwJTkxJUU0JUJCJUEzJUU3JTkwJTg2&#34;&gt;前向代理&lt;/span&gt;不同，前向代理作为客户端的代理，将从互联网上获取的资源返回给一个或多个的客户端，服务端 (如 Web 服务器) 只知道代理的 IP 地址而不知道客户端的 IP 地址；而反向代理是作为服务器端 (如 Web 服务器) 的代理使用，而不是客户端。客户端借由前向代理可以间接访问很多不同互联网服务器 (集群) 的资源，而反向代理是供很多客户端都通过它间接访问不同后端服务器上的资源，而不需要知道这些后端服务器的存在，而以为所有资源都来自于这个反向代理服务器.&lt;/p&gt;
&lt;p&gt;反向代理在现时的互联网中并不少见，而另一些例子，像是&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvJUU1JTg1JUE3JUU1JUFFJUI5JUU1JTgyJUIzJUU5JTgxJTlFJUU3JUI2JUIyJUU4JUI3JUFG&#34;&gt; CDN&lt;/span&gt;、SNI 代理等，是反向代理结合&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC53aWtpcGVkaWEub3JnL3dpa2kvRE5T&#34;&gt; DNS&lt;/span&gt; 的一类延伸应用.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/archives/422/attachment/5&#34;&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/5.webp&#34; alt=&#34;&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;正向代理与反向代理的区别&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#正向代理与反向代理的区别&#34;&gt;#&lt;/a&gt; 正向代理与反向代理的区别&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;正向代理是需要在用户的电脑上配置正向代理服务器的；而反向代理不需要，因为用户是直接访问的反向代理服务器&lt;/li&gt;
&lt;li&gt;正向代理的应用场景是用户是知道目标服务器的地址，如:&lt;a href=&#34;www.google.com&#34;&gt;www.google.com&lt;/a&gt;, 但不能直接访问，那么就需要在用户电脑配置一个正向代理服务器，用户再次访问&lt;a href=&#34;www.google.com&#34;&gt; www.google.com&lt;/a&gt; 就可以正常访问了；而反向代理的应用场景是用户本来就不知道目标服务器的地址。而是由平台方提供一个反向代理服务器的地址，用户直接访问反向代理服务器的地址就行如&lt;a href=&#34;wordpress-1258894728.cos.ap-beijing.myqcloud.com&#34;&gt; wordpress-1258894728.cos.ap-beijing.myqcloud.com&lt;/a&gt; 不管目标服务器有多少，用户不需要关心，只要访问反向代理服务器就 ok; 由反向代理服务器去解析访问目标服务器&lt;/li&gt;
&lt;li&gt;反向代理极大的保护了应用的安全性，而且此结构可以很好的搭建负载均衡&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;如果想要网站响应速度快，肯定少不了进行网站优化，比如开启各种缓存，像&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93b3JkcHJlc3MtMTI1ODg5NDcyOC5jb3MuYXAtYmVpamluZy5teXFjbG91ZC5jb20vYXJjaGl2ZXMvNzU=&#34;&gt; Memcached&lt;/span&gt; 缓存，Opcache 缓存等等。这里记录一下 Opcache 设置教程。&lt;/p&gt;
&lt;h2 id=&#34;什么是opcache呢&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是opcache呢&#34;&gt;#&lt;/a&gt; 什么是 Opcache 呢？&lt;/h2&gt;
&lt;p&gt;Opcache 的前生是  &lt;code&gt;Optimizer+&lt;/code&gt;  ，它是 PHP 的官方公司 Zend 开发的一款闭源但可以免费使用的 PHP 优化加速组件。 Optimizer+ 将 PHP 代码预编译生成的脚本文件  &lt;code&gt;Opcode&lt;/code&gt;  缓存在共享内存中供以后反复使用，从而避免了从磁盘读取代码再次编译的时间消耗。同时，它还应用了一些代码优化模式，使得代码执行更快。从而加速 PHP 的执行。 PHP 的正常执行流程如下 &lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/20210909100618.png&#34; alt=&#34;&#34;&gt; request 请求（nginx,apache,cli 等）–&amp;gt;Zend 引擎读取.php 文件–&amp;gt; 扫描其词典和表达式 --&amp;gt; 解析文件–&amp;gt; 创建要执行的计算机代码 (称为 Opcode)–&amp;gt; 最后执行 Opcode–&amp;gt; response 返回 每一次请求 PHP 脚本都会执行一遍以上步骤，如果 PHP 源代码没有变化，那么 Opcode 也不会变化，显然没有必要每次都重新生成 Opcode，结合在 Web 中无所不在的缓存机制，我们可以把 Opcode 缓存下来，以后直接访问缓存的 Opcode 岂不是更快，启用 Opcode 缓存之后的流程图如下所示： &lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/QQ%E6%88%AA%E5%9B%BE20210909100706.png&#34; alt=&#34;&#34;&gt; Opcode cache 的目地是避免重复编译，减少 CPU 和内存开销。&lt;/p&gt;
&lt;h2 id=&#34;下面介绍opcache的安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#下面介绍opcache的安装&#34;&gt;#&lt;/a&gt; 下面介绍 Opcache 的安装&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;1、找到opcache的扩展，我的是php7.4
yum list php74*
2、安装扩展
yum install php74-php-opcache.x86_64 -y
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;php配置文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#php配置文件&#34;&gt;#&lt;/a&gt; PHP 配置文件&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;[root@centos opt]# find / -name php.ini #查找php.ini文件位置 
/etc/opt/remi/php74/php.ini
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;编辑配置文件，找到 &lt;code&gt;[opcache]&lt;/code&gt;  加入&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.enable=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;此参数的值为 1 代表开启 Opcache，值为 0 代表关闭 Opcache，默认值为 1。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.memory_consumption=512
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;此参数的值代表 Opcache 占用内存的大小，单位是 MB，默认值为 64。建议根据服务器内存情况来设置&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.interned_strings_buffer=64
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;此参数的值的单位是 MB，默认值为 8，建议根据服务器内存大小，设置一个大于 64 的值即可。 PHP 使用了一种叫做字符串驻留（string interning）的技术来改善性能。例如，如果你在代码中使用了 1000 次字符串 foobar，Zend 引擎在第一次使用这个字符串时会分配一个不可变的内存区域来存储这个字符串，之后的 999 次都会直接引用这个内存区域，而不需要重复创建。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.max_accelerated_files=3000
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Zend 引擎在第一次执行某 PHP 文件后，会将该文件的 OPcode 存储在哈希表中，之后的请求直接从哈希表中找到相应文件的 OPcode，从而达到性能优化，而此配置选项决定了可以存储的 PHP 文件数量上限。 Zend 引擎对此配置参数的真实取值是在质数集合 {223, 463, 983, 1979, 3907, 7963, 16229, 32531, 65407, 130987} 中找到的第一个大于等于参数值的质数，例如设置此参数的值为 222，则真实取值为 223。 那么如何知道我们应用中的 PHP 文件数量呢？进入应用目录，一般这里指的是进入我们 WordPress 的站点根目录，使用如下命令即可查看应用中的 PHP 文件数量：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@VM-8-7-centos wordpress-1258894728.cos.ap-beijing.myqcloud.com]# cd /root/jiangjiyue/wordpress-1258894728.cos.ap-beijing.myqcloud.com/ 
[root@VM-8-7-centos wordpress-1258894728.cos.ap-beijing.myqcloud.com]# find . -type f -print  grep php  wc -l 
1292
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;PHP 文件数量为 1292，所以我将该参数的值设置为 3000。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.validate_timestamps=0
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;如果此参数的值设置为 1，那么 Zend 引擎在收到请求时，会每隔一段时间检测一次被请求的 PHP 文件是否已更新。如果文件已更新，就会重新对该文件进行语法分析、编译等步骤，生成新的 Opcode。 检测的周期是根据另一个参数  &lt;code&gt;opcache.revalidate_freq&lt;/code&gt;  而定的，每次检测都是一次 stat 系统调用，众所周知，系统调用会消耗一些 CPU 时间，并且 stat 系统调用会进行磁盘 I/O，更加浪费性能。 不仅如此，假设你对服务器中的 PHP 文件进行了一次大量的更新，更新的过程中部分旧的文件会因为未过期而依然生效，和部分已生效的新文件混合在一起产生作用，必然会产生不确定因素，带来很多麻烦，&lt;strong&gt;所以建议将此参数的值设置为 0&lt;/strong&gt; 。 不过需要注意的是，设置为 0 后，无论你怎么更新文件，Zend 引擎都会使用已缓存的 Opcode，除非重启 php-fpm 或使用  &lt;code&gt;opcache_reset()&lt;/code&gt;  方法清空缓存，当然下面我也会提供 Opcache-gui (通过 Web 界面管理，可以重置缓存)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.save_comments=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;如果禁用，脚本文件中的注释内容将不会被包含到操作码缓存文件， 这样可以有效减小优化后的文件体积。 禁用此配置指令可能会导致一些依赖注释或注解的 应用或框架无法正常工作， 比如： Doctrine， Zend Framework 2 以及 PHPUnit. 所以这里启用&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.file_update_protection=0
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;当 Zend 引擎执行某 PHP 文件时，如果该文件的 Modify 时间戳 距当前时间的差值小于此参数的值，则该文件不会被缓存，此参数值的单位为秒，默认为 2。 此参数的目的是为了防止文件还未修改完成就被 Opcache 缓存了，从而产生错误。而实际生产环境中，我们将  &lt;code&gt;opcache.validate_timestamps&lt;/code&gt;  设置为 0，文件只要被访问一次，就会被永久缓存，除非重启 php-fpm 才会刷新缓存，所以此参数没什么用，还浪费性能，建议设置为 0。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;opcache.huge_code_pages=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;众所周知，Linux 系统默认内存是以 4KB 进行分页的，而虚拟地址和内存地址是需要转换的，转换过程需要进行查表，CPU 为了加速查表会内建 TLB（Translation Lookaside Buffer），而 TLB 的大小是有限的，分页越小，表里的条目也就越多，TLB 的 Cache Miss 也就越高。 所以我们如果启用大内存页，就能间接降低 TLB 的 Cache Miss，而 Opcache 也能使用 Hugepage 来缓存 Opcodes，从而达到性能优化的目的。 此参数值为 1 即可开启以上功能，默认值为 0。 设置完后还没正式开启，需要系统开启 Hugepage 功能，使用如下命令可以查看当前系统 Hugepage 的信息：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@centos wordpress-1258894728.cos.ap-beijing.myqcloud.com]# cat /proc/meminfo  grep Huge AnonHugePages: 133120 kB 
HugePages_Total: 0 
HugePages_Free: 0 
HugePages_Rsvd: 0 
HugePages_Surp: 0 
Hugepagesize: 2048 kB
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看到 HugePages_Total 等参数的值为 0，也就是未开启 HugePages 功能。&lt;/p&gt;
&lt;p&gt;运行如下命令即可开启 HugePages，其中 128 代表 HugePages 的大小，单位是 MB：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sysctl vm.nr_hugepages=128
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;建议根据服务器内存情况进行分配 HugePages，例如服务器是 2G，设置为 128，可以自行参考进行设置&lt;/p&gt;
&lt;h2 id=&#34;最终配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#最终配置&#34;&gt;#&lt;/a&gt; 最终配置&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/20210909103033.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;opcache-gui&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#opcache-gui&#34;&gt;#&lt;/a&gt; Opcache-gui&lt;/h2&gt;
&lt;p&gt;这里使用的 gui 界面是 amnuts 分享的&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2FtbnV0cy9vcGNhY2hlLWd1aQ==&#34;&gt; opcache-gui&lt;/span&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 进入opt目录
cd /opt
# 安装git
yum install -y git
# 克隆项目到本地
wget https://github.com/amnuts/opcache-gui.git
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后将项目中的 index.php 移到您的 Web 服务器可以加载的位置。然后将浏览器指向该位置，例如 &lt;code&gt;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/Opcache-gui-zn.php&lt;/code&gt;  [c-alert type=“warning”] 一定要重启 PHP-FPM 服务 [/c-alert] 如图: &lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/opcache-English.png&#34; alt=&#34;&#34;&gt; 我将此文件进行了大概的汉化 [c-downbtn type=“github” url=“&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9yYXcuZ2l0aHVidXNlcmNvbnRlbnQuY29tL0ppYW5nSmlZdWUveXVud2VpL21haW4vT3BjYWNoZS1ndWktem4ucGhw&#34;&gt;https://raw.githubusercontent.com/JiangJiYue/yunwei/main/Opcache-gui-zn.php&lt;/span&gt;”] Opcache 汉化下载 [/c-downbtn] &lt;img data-src=&#34;https://wordpress-1258894728.cos.ap-beijing.myqcloud.com/wp-content/uploads/2021/09/cache-ZN.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;安装libmemcached扩展&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装libmemcached扩展&#34;&gt;#&lt;/a&gt; 安装 libmemcached 扩展&lt;/h2&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;wget&lt;/span&gt; https://launchpad.net/libmemcached/1.0/1.0.18/+download/libmemcached-1.0.18.tar.gz&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;tar&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-xvzf&lt;/span&gt; libmemcached-1.0.18.tar.gz&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;cd&lt;/span&gt; libmemcached-1.0.18&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;./configure --with-memcached --disable-memcached-sasl&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;安装memcached扩展&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装memcached扩展&#34;&gt;#&lt;/a&gt; 安装 memcached 扩展&lt;/h2&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;wget&lt;/span&gt; http://pecl.php.net/get/memcached-3.1.3.tgz&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;tar&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-zxvf&lt;/span&gt; memcached-3.1.3.tgz&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;cd&lt;/span&gt; memcached-3.1.3&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;首先使用 phpize 生成文件 如果 php 加了环境变量一般直接执行 &lt;code&gt;phpize&lt;/code&gt;  就行了 如果找不到 phpize 使用查找命令 &lt;code&gt;find / -name phpize&lt;/code&gt;  搜索到文件，我的在 &lt;code&gt;/usr/local/bin/phpize&lt;/code&gt;  目录，然后执行&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;/usr/local/bin/phpize&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;不知道 &lt;code&gt;php-config&lt;/code&gt;  在哪个目录 使用 find 方法&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;find&lt;/span&gt; / &lt;span class=&#34;token parameter variable&#34;&gt;-name&lt;/span&gt; php-config&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这里需要将刚才安装的 &lt;code&gt;libmemcached&lt;/code&gt;  的目录关联&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;find&lt;/span&gt; / &lt;span class=&#34;token parameter variable&#34;&gt;-name&lt;/span&gt; libmemcached&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;开始安装&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;./configure --with-php-config&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;/usr/bin/php-config  --with-libmemcached-dir&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;/usr/local  --disable-memcached-sasl&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;提示 &lt;code&gt;Installing shared extensions: /usr/lib64/php/modules/&lt;/code&gt;  安装成功 在 &lt;code&gt;php.ini&lt;/code&gt;  中添加&lt;/p&gt;
&lt;figure class=&#34;highlight ini&#34;&gt;&lt;figcaption data-lang=&#34;ini&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token section&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token section-name selector&#34;&gt;memcached&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key attr-name&#34;&gt;extension&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token value attr-value&#34;&gt;memcached.so&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;查看 &lt;code&gt;php.ini&lt;/code&gt;  位置&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;php &lt;span class=&#34;token parameter variable&#34;&gt;-igrep&lt;/span&gt; php.ini&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;执行 &lt;code&gt;php -m&lt;/code&gt;  查看扩展是否成功安装&lt;/p&gt;
&lt;h2 id=&#34;安装-memcached&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装-memcached&#34;&gt;#&lt;/a&gt; 安装 Memcached&lt;/h2&gt;
&lt;p&gt;Linux 系统安装 memcached，首先要先安装 libevent 库。&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; libevent libevent-devel&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;安装-memcached-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装-memcached-2&#34;&gt;#&lt;/a&gt; 安装 Memcached&lt;/h2&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; memcached&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;Memcached 运行 Memcached 命令的运行： 作为前台运行:&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;memcached &lt;span class=&#34;token parameter variable&#34;&gt;-p&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;11211&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-m&lt;/span&gt; 64m &lt;span class=&#34;token parameter variable&#34;&gt;-vv&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;作为后台服务运行：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;memcached &lt;span class=&#34;token parameter variable&#34;&gt;-d&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-m&lt;/span&gt; 64M &lt;span class=&#34;token parameter variable&#34;&gt;-u&lt;/span&gt; root &lt;span class=&#34;token parameter variable&#34;&gt;-l&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;127.0&lt;/span&gt;.0.1 &lt;span class=&#34;token parameter variable&#34;&gt;-p&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;11211&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-c&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-P&lt;/span&gt; /tmp/memcached.pid&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;启动选项：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;-d 是启动一个守护进程；&lt;/li&gt;
&lt;li&gt;-m 是分配给 Memcache 使用的内存数量，单位是 MB；&lt;/li&gt;
&lt;li&gt;-u 是运行 Memcache 的用户；&lt;/li&gt;
&lt;li&gt;-l 是监听的服务器 IP 地址，可以有多个地址；&lt;/li&gt;
&lt;li&gt;-p 是设置 Memcache 监听的端口，，最好是 1024 以上的端口；&lt;/li&gt;
&lt;li&gt;-c 是最大运行的并发连接数，默认是 1024；&lt;/li&gt;
&lt;li&gt;-P 是设置保存 Memcache 的 pid 文件。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;查找允许 memcached 的进程 id:&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;ps&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-efgrep&lt;/span&gt; memcached&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;root      &lt;span class=&#34;token number&#34;&gt;9662&lt;/span&gt;     &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;  &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;:13 ?        00:00:00 /usr/bin/memcached &lt;span class=&#34;token parameter variable&#34;&gt;-d&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-m&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1024&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-u&lt;/span&gt; root &lt;span class=&#34;token parameter variable&#34;&gt;-l&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;127.0&lt;/span&gt;.0.1 &lt;span class=&#34;token parameter variable&#34;&gt;-p&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;11211&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-c&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1024&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-P&lt;/span&gt; /tmp/memcached.pid&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;root     &lt;span class=&#34;token number&#34;&gt;10155&lt;/span&gt;  &lt;span class=&#34;token number&#34;&gt;8703&lt;/span&gt;  &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;:14 pts/0    00:00:00 &lt;span class=&#34;token function&#34;&gt;grep&lt;/span&gt; memcached&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;测试 使用 telnet 命令测试能否连接成功&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;telnet &lt;span class=&#34;token number&#34;&gt;127.0&lt;/span&gt;.0.1 &lt;span class=&#34;token number&#34;&gt;11211&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;出现以上内容代表成功&lt;/p&gt;
